    `live_flag` BOOLEAN COMMENT 'Whether broadcast is live',
    `network` STRING COMMENT 'Network on which broadcast airs',
    `nielsen_program_code` STRING COMMENT 'Nielsen program identification code for audience measurement',
    `notes` STRING COMMENT 'Additional broadcast notes',
