    `omc_concept_role` STRING COMMENT 'MovieLabs OMC structural concept role for this entity: Context',
    `omc_context_code` BIGINT COMMENT 'OMC Context identifier grouping this production entity into a creative/production context',
    `omc_participant_code` BIGINT COMMENT 'OMC Participant identifier (person/organization/service performing or owning this entity)',
    `platform_type` STRING COMMENT '',
    `preemption_reason` STRING COMMENT 'Reason for preemption if broadcast was preempted',
    `repeat_number` STRING COMMENT 'Sequential count of how many times this episode has been broadcast on this channel/platform. 0 = original airing, 1+ = repeat. Critical for rights management and audience measurement.',
    `runtime_seconds` STRING COMMENT 'Total runtime in seconds',
    `sap_language` STRING COMMENT 'Secondary Audio Program language if available',
